module JK_latch (  
    input J,  
    input K,  
    input CLK,  
    output reg Q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin  
        if (J && ~K)  
            Q <= 1;  // Set  
        else if (~J && K)  
            Q <= 0;  // Reset  
        else if (J && K)  
            Q <= ~Q; // Toggle  
    end  
endmodule
